/* ================= PRODUCTS ================= */
export function useProducts() {
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);

  const fetchProducts = async () => {
    try {
      const { data, error } = await supabase
        .from('products')
        .select('*')
        .eq('is_active', true)
        .order('created_at', { ascending: false });

      if (error) {
        console.error('Error fetching products:', error);
        setProducts(FALLBACK_PRODUCTS);
      } else if (data && data.length > 0) {
        const mappedProducts: Product[] = data.map((item: any) => ({
          id: item.id,
          name: item.name,
          category: item.category,
          subCategory: item.sub_category,
          collection: item.collection,
          occasion: item.occasion || [],
          price: item.price,
          offerPrice: item.offer_price,
          offerPercent: item.offer_percent,
          images: item.images || [],
          rating: item.rating || 0,
          reviewCount: item.review_count || 0,
          inStock: item.in_stock,
          variants: item.variants || [],
          material: item.material || '',
          weight: item.weight || '',
          description: item.description || '',
          isActive: item.is_active,
          createdAt: item.created_at,
          updatedAt: item.updated_at
        }));
        setProducts(mappedProducts);
      } else {
        console.warn('No products found in database, using fallback data');
        setProducts(FALLBACK_PRODUCTS);
      }
    } catch (err) {
      console.error('Failed to fetch products:', err);
      setProducts(FALLBACK_PRODUCTS);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchProducts();
  }, []);

  return { products, loading };
}

/* ================= CATEGORIES ================= */
export function useCategories() {
  const [categories, setCategories] = useState<Category[]>([]);
  const [loading, setLoading] = useState(true);

  const fetchCategories = async () => {
    try {
      console.log('Fetching categories from Supabase...');
      
      const { data, error } = await supabase
        .from('categories')
        .select('*')
        .eq('is_active', true)
        .order('display_order', { ascending: true });

      if (error) {
        console.error('Error fetching categories:', error);
        setCategories(FALLBACK_CATEGORIES);
      } else if (data && data.length > 0) {
        const mappedCategories: Category[] = data.map((item: any) => ({
          id: item.id,
          name: item.name,
          slug: item.slug,
          image: item.image,
          images: item.images || [],
          subCategories: Array.isArray(item.sub_categories) ? item.sub_categories : 
                         (typeof item.sub_categories === 'string' ? JSON.parse(item.sub_categories) : []),
          featured: item.featured || false,
          isActive: item.is_active,
          displayOrder: item.display_order
        }));
        setCategories(mappedCategories);
      } else {
        console.warn('No categories found in database, using fallback data');
        setCategories(FALLBACK_CATEGORIES);
      }
    } catch (err) {
      console.error('Failed to fetch categories:', err);
      setCategories(FALLBACK_CATEGORIES);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchCategories();
  }, []);

  return { categories, loading };
}

/* ================= HERO ================= */
export function useHeroImages() {
  const [heroImages, setHeroImages] = useState<HeroImage[]>([]);
  const [loading, setLoading] = useState(true);

  const fetchHeroImages = async () => {
    try {
      const { data, error } = await supabase
        .from('hero_images')
        .select('*')
        .eq('is_active', true)
        .order('display_order', { ascending: true });

      if (error) {
        console.error('Error fetching hero images:', error);
        setHeroImages(FALLBACK_HERO_IMAGES);
      } else if (data && data.length > 0) {
        const mappedHeroImages: HeroImage[] = data.map((item: any) => ({
          id: item.id,
          image_url: item.image_url,
          title: item.title,
          subtitle: item.subtitle,
          cta_text: item.cta_text,
          cta_link: item.cta_link,
          order: item.display_order,
          isActive: item.is_active
        }));
        setHeroImages(mappedHeroImages);
      } else {
        console.warn('No hero images found in database, using fallback data');
        setHeroImages(FALLBACK_HERO_IMAGES);
      }
    } catch (err) {
      console.error('Failed to fetch hero images:', err);
      setHeroImages(FALLBACK_HERO_IMAGES);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchHeroImages();
  }, []);

  return { heroImages, loading };
}

/* ================= CONFIG ================= */
export function useSiteConfig() {
  const [config, setConfig] = useState<Record<string, any>>({});

  const fetchConfig = async () => {
    try {
      const { data, error } = await supabase
        .from('site_config')
        .select('key, value');

      if (error) {
        console.error('Error fetching config:', error);
        setConfig({ hero_badge: 'Spring Collection 2026' });
      } else if (data && data.length > 0) {
        const map: Record<string, any> = {};
        data?.forEach(item => (map[item.key] = item.value));
        setConfig(map);
      } else {
        setConfig({ hero_badge: 'Spring Collection 2026' });
      }
    } catch (err) {
      console.error('Failed to fetch config:', err);
      setConfig({ hero_badge: 'Spring Collection 2026' });
    }
  };

  useEffect(() => {
    fetchConfig();
  }, []);

  return { config };
}